solucao:
frase = 'o gato e o rato e o cachorro'
contagem = {}
for palavra in frase.split():
    contagem[palavra] = contagem.get(palavra, 0) + 1
for palavra in sorted(contagem):
    print(f'{palavra}: {contagem[palavra]}')
